def run(cmd, cwd=None, env=None):
    p = subprocess.run(cmd, cwd=cwd, env=env, text=True)
    if p.returncode != 0:
        raise SystemExit(p.returncode)


def ensure_dir(p: Path):
    p.mkdir(parents=True, exist_ok=True)


def read_requirements(req_file: Path):
    if not req_file.exists():
        return []
    lines = req_file.read_text(encoding="utf-8").splitlines()
    reqs = []
    for line in lines:
        s = line.strip()
        if not s or s.startswith("#"):
            continue
        reqs.append(s)
    return reqs


def should_exclude(rel_posix: str, exclude_patterns):
    for pat in exclude_patterns:
        if Path(rel_posix).match(pat):
            return True
    return False


def add_tree_to_zip(zf: zipfile.ZipFile, src_root: Path, arc_prefix: str, exclude_patterns):
    src_root = src_root.resolve()
    for p in src_root.rglob("*"):
        if p.is_dir():
            continue
        rel = p.relative_to(src_root).as_posix()
        if should_exclude(rel, exclude_patterns):
            continue
        arcname = f"{arc_prefix}/{rel}" if arc_prefix else rel
        zf.write(p, arcname)


def add_file_to_zip(zf: zipfile.ZipFile, path: Path, arcname: str):
    if path.exists() and path.is_file():
        zf.write(path, arcname)


